/* Returns the temperature value for a given fluoresence. Requires the curve generated by heatgen.
 *
 * Args:
 *  temp: The temperature to be compared to the standard curve.
 * 
 * Returns:
 *  Success: Fluoresence for the requested temperature.
 *  Failure: -1. 
 */
double fluorquery(double fluor)
{
    for(int i = 0; i < fluorkey.size(); i++) // For the length of our fluoresence key:
    {
        if(fluorkey[i] > fluor) // If the current value in the key is higher than our target fluoresence:
        {
            return tempkey[i]; // Return the corresponding temperature.
        }
    }
    return -1; // Else, return -1 to indicate failure.
}

/* Returns the fluoresence value for a given temperature. Requires the curve generated by heatgen.
 *
 * Args:
 *  temp: The temperature to be compared to the standard curve.
 * 
 * Returns:
 *  Success: Fluoresence for the requested temperature.
 *  Failure: -1. 
 */
double heatquery(double temp)
{
    for(int i = 0; i < fluorkey.size(); i++) // For the length of our fluoresence key:
    {
        if(tempkey[i] > temp) // If the current value in the key is higher than our target temperature:
        {
            return fluorkey[i]; //Return the corresponding fluoresence.
        }
    }
    return -1; // Else, return a negative 1--temperature out of our keyed range.
}

