/*
 * Holds at temperature for a given period of time. This function also requires heatgen to have populated relevant curves.
 * 
 * Args: 
 *  Temp: temperature to be held at.
 *  Time: Time in seconds to hold.
 */
void holdtemp(double temp, double time)
{
    // Turn the heater on.
    digitalWrite(HEATER_PIN,HIGH);

    // Retrieve our target fluoresence from our heating curves.
    double fluortarget = heatquery(temp);
    while(y[y.size()-1] < fluortarget) // While we're below the temperature of interest, heat:
    {
        delay(10);
    }
    int start = 0;
    double ycurrent;
    cout << "Activate hold." << endl; // Log that we're holding to the console.
    while(start < time * 100)
    {
        ycurrent = y[y.size()-1];
        if (ycurrent < fluortarget - 20) // If our current fluoresence is below the target minus 20:
        {
            digitalWrite(HEATER_PIN, HIGH); // Turn the heater on.
        }
        else if (ycurrent > fluortarget) // If it's above the target:
        {
            digitalWrite(HEATER_PIN, LOW); // Turn the heater off.
        }
        delay(10); // Wait 10 milliseconds before checking again.
        start++; // Increment our wait.
    }
}


/*
 * Waits for the temperature to reach a certain value based on the curve created by heatgen. For the current functionality, it only operates for falling.
 * 
 * Args:
 *  Temp: temperature to fall to.
 */
void waittotemp(double temp)
{
    double fluortarget = heatquery(temp); // Retrieve the target fluoresence from the curves. 
    cout << "Falling." << endl; // Log that we're falling.
    while(y[y.size()-1] > fluortarget)
    {
        delay(10); // Wait until we've dropped enough.
    }
}